{
  "competency_groups": [
    {
      "code": "C1",
      "title": "The Living World: Classification and Taxonomy",
      "description": "Master the fundamental principles of biodiversity, taxonomic hierarchy, and binomial nomenclature.",
      "competencies": [
        "Explain the need for classification and describe the three domains of life."
      ],
      "unit_name": "Diversity of Living Organisms",
      "chapter_name": "The Living World"
    },
    {
      "code": "C2",
      "title": "Biological Classification: Five Kingdoms and Microbes",
      "description": "Analyze the five-kingdom system and identify characteristics of Monera, Protista, Fungi, Lichens, Viruses, and Viroids.",
      "competencies": [
        "Classify organisms into kingdoms based on salient features."
      ],
      "unit_name": "Diversity of Living Organisms",
      "chapter_name": "Biological Classification"
    },
    {
      "code": "C3",
      "title": "Plant Kingdom: Major Groups and Features",
      "description": "Differentiate between major plant groups including Algae, Bryophyta, Pteridophyta, Gymnospermae, and Angiosperms.",
      "competencies": [
        "Distinguish the salient features of all major plant divisions."
      ],
      "unit_name": "Diversity of Living Organisms",
      "chapter_name": "Plant Kingdom"
    },
    {
      "code": "C4",
      "title": "Animal Kingdom: Phyla and Classes",
      "description": "Classify animals based on body organization, distinguishing between non-chordates (up to phylum) and chordates (up to class).",
      "competencies": [
        "Identify key characteristics of animal groups from invertebrates to vertebrates."
      ],
      "unit_name": "Diversity of Living Organisms",
      "chapter_name": "Animal Kingdom"
    },
    {
      "code": "C5",
      "title": "Morphology of Flowering Plants: Structural Adaptations",
      "description": "Describe the morphology and modifications of root, stem, leaf, inflorescence, flower, fruit, and seed.",
      "competencies": [
        "Analyze morphological structures to identify plant adaptations."
      ],
      "unit_name": "Structural Organization in Plants and Animals",
      "chapter_name": "Morphology of Flowering Plants"
    }
  ]
}
